// ── Test: Wronskian identity at large order ──
// I_v(z) * K_{v+1}(z) + I_{v+1}(z) * K_v(z) = 1/z

#[test]
fn wronskian_ik_large_order() {
    let test_cases: Vec<(f64, Complex<f64>)> = vec![
        (100.0, Complex::new(50.0, 30.0)),
        (90.0, Complex::new(40.0, 20.0)),
        (100.0, Complex::new(1.0, 10.0)), // region 2
    ];

    for (fnu, z) in &test_cases {
        let i_result = besseli_seq(*fnu, *z, 2, Scaling::Unscaled)
            .unwrap_or_else(|e| panic!("I_{fnu}({z}): {e:?}"));
        let k_result = besselk_seq(*fnu, *z, 2, Scaling::Unscaled)
            .unwrap_or_else(|e| panic!("K_{fnu}({z}): {e:?}"));

        let iv = i_result.values[0];
        let iv1 = i_result.values[1];
        let kv = k_result.values[0];
        let kv1 = k_result.values[1];

        // Wronskian: I_v * K_{v+1} + I_{v+1} * K_v = 1/z
        let wronsk = iv * kv1 + iv1 * kv;
        let expected = Complex::new(1.0, 0.0) / z;
        let err = (wronsk - expected).norm() / expected.norm();
        assert!(
            err < 1e-12,
            "Wronskian I·K at fnu={fnu}, z={z}: rel err = {err:.2e}"
        );
    }

    eprintln!(
        "  wronskian_ik_large_order: {} test cases passed (tol=1e-12)",
        test_cases.len()
    );
}
